typedef StatusListener = void Function(String status);

class SourceBinding {
  SourceBinding(this._listener);

  final StatusListener _listener;
  bool _closed = false;

  bool get isClosed => _closed;

  void deliverLive(String status) {
    if (!_closed) {
      _listener(status);
    }
  }

  void deliverQueued(String status) {
    _listener(status);
  }

  void close() {
    _closed = true;
  }
}

class ManualStatusSource {
  final List<SourceBinding> bindings = <SourceBinding>[];

  SourceBinding bind(StatusListener listener) {
    final binding = SourceBinding(listener);
    bindings.add(binding);
    return binding;
  }
}

