class LeasePool {
  final Set<String> _owners = <String>{};
  bool _transportWanted = false;

  void add(String owner) {
    _owners.add(owner);
    _transportWanted = true;
  }

  void remove(String owner) {
    _owners.remove(owner);
    _transportWanted = false;
  }

  bool get transportWanted => _transportWanted;
  int get ownerCount => _owners.length;
}

