import 'epoch_filter.dart';
import 'lease_pool.dart';
import 'source.dart';

class ConnectivityMonitor {
  ConnectivityMonitor(this.source, {LeasePool? leases, EpochFilter? epochs})
      : leases = leases ?? LeasePool(),
        epochs = epochs ?? EpochFilter();

  final ManualStatusSource source;
  final LeasePool leases;
  final EpochFilter epochs;
  final Map<String, StatusListener> _listeners = <String, StatusListener>{};
  SourceBinding? _binding;
  String? _latest;

  String? get latest => _latest;

  void attach(String owner, StatusListener listener) {
    if (_listeners.containsKey(owner)) {
      throw StateError('owner already attached: $owner');
    }
    _listeners[owner] = listener;
    leases.add(owner);
    if (leases.transportWanted && _binding == null) {
      final epoch = epochs.open();
      _binding = source.bind((status) => _accept(epoch, status));
    }
  }

  void detach(String owner) {
    _listeners.remove(owner);
    leases.remove(owner);
    if (!leases.transportWanted && _binding != null) {
      _binding!.close();
      _binding = null;
      epochs.close();
    }
  }

  void _accept(int epoch, String status) {
    if (!epochs.accepts(epoch)) return;
    _latest = status;
    for (final listener in List<StatusListener>.of(_listeners.values)) {
      listener(status);
    }
  }
}

