import '../lib/connectivity_monitor.dart';
import '../lib/source.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final source = ManualStatusSource();
  final monitor = ConnectivityMonitor(source);
  final primaryEvents = <String>[];
  monitor.attach('primary', primaryEvents.add);
  check(source.bindings.length == 1, 'the first owner starts one source binding');
  source.bindings.single.deliverLive('offline');
  source.bindings.single.deliverLive('online');
  check(
    primaryEvents.join(',') == 'offline,online',
    'live source transitions reach an attached owner',
  );
  monitor.detach('primary');
  check(source.bindings.single.isClosed, 'the final owner releases the source');

  final sharedSource = ManualStatusSource();
  final shared = ConnectivityMonitor(sharedSource);
  final left = <String>[];
  final right = <String>[];
  shared.attach('left', left.add);
  shared.attach('right', right.add);
  sharedSource.bindings.single.deliverLive('metered');
  check(left.single == 'metered', 'the first owner receives a shared update');
  check(right.single == 'metered', 'the second owner receives a shared update');
}
